// router.js
import Vue from 'vue'
import {
	RouterMount,
	createRouter,
	runtimeQuit
} from 'uni-simple-router';
import store from '@/store/index.js'

// 白名单
let whiteList = () => {
	return store.getters.whitePageList
}

const router = createRouter({
	platform: process.env.VUE_APP_PLATFORM,
	routes: [...ROUTES, {
		path: '*',
		redirect: (to) => {
			return {
				name: 'home'
			}
		}
	}],
	routerErrorEach: ({
		type,
		level,
		...args
	}) => {












	},
});


//全局路由前置守卫
router.beforeEach(async (to, from, next) => {
	const token = store.getters.token
	if (to.query.pid) {
		uni.setStorage({
			key: 'pid',
			data: to.query.pid
		})
	}
	if (store.getters.diyPageList.includes(to.path)) {
		// 预加载diy页面主题方案
		let d = await store.dispatch('reploadCachePageTheme', to.path)
		console.log(`当前主题方案：${d}`)
	}
	if (token) {
		if (to.path == '/pages/user/login') {
			next({
				path: '/pages/index/index',
				NAVTYPE: 'pushTab'
			})
		} else {
			next()
		}
	} else {
		if (whiteList().indexOf(to.path) !== -1) {
			next()
		} else {
			// Vue.prototype.$util.msg('用户未登录，无法访问页面！')
			console.log('用户未登录，无法访问页面！')
			next({
				path: `/pages/user/login`,
				query: {
					redirect: Vue.prototype.$util.getRedirectUrl(to.path, to.query)
				},
				NAVTYPE: 'push'
			})
		}
	}
})
// 全局路由后置守卫
router.afterEach((to, from) => {
	// console.log(`from:${from.path},to:${to.path}.跳转结束`)
})

export {
	router,
	RouterMount
}