import config from "common/config"

// 目前onLoad,onShow,onHide没有注册到组件中，所以$page.mixin只会对page组件进行混合
module.exports = {
	onLoad() {
		// 设置页面微信公众号H5分享数据

		if (this.$util.browserType().weixin != true)
			return

		let queryParams = {}
		const pid = uni.getStorageSync('pid')
		if (pid)
			queryParams.pid = pid

		queryParams = Object.assign(queryParams, this.$Route.query)
		let link = config.apiurl + this.$util.getRedirectUrl(this.$Route.path, queryParams)
		let fullPath = config.apiurl + this.$Route.fullPath

		// const {
		// 	basic_system_name,
		// 	basic_system_description,
		// 	logo
		// } = this.sysconfig
		const {
			sysconfig: {
				basic_system_name,
				basic_system_description,
				logo
			}
		} = uni.getStorageSync('kss_lifeData')

		this.$wxH5share({
			url: fullPath,
			share_data: {
				title: basic_system_name,
				desc: basic_system_description,
				imgUrl: this.$util.img(logo),
				link: link, // 分享链接，该链接域名或路径必须与当前页面对应的公众号 JS 安全域名一致
			}
		})

	},
}