import 'uni-pages';import 'uni-h5';import Vue from 'vue'
import App from './App'
import uView from "uview-ui";

Vue.use(uView);
//工具处理
import util from "common/util.js";
Vue.use(util);
import kss from "common/kss.js";
Vue.use(kss);

import config from "common/config.js";
// 此处为演示vuex使用，非uView的功能部分
import store from '@/store'
Vue.config.productionTip = false



// // 引入uView提供的对vuex的简写法文件
let vuexStore = require('@/store/$u.mixin.js')
Vue.mixin(vuexStore)


// // 引入uView对小程序分享的mixin封装
let mpShare = require('uview-ui/libs/mixin/mpShare.js');
Vue.mixin(mpShare)



import wx from 'weixin-js-sdk'
Vue.prototype.$wx = wx
import {
	wxH5share
} from '@/common/jweixin.js'
Vue.prototype.$wxH5share = wxH5share
// 让每个page页面初始化微信公众号的分享数据
let wxShareH5 = require('@/store/$wxShareH5.mixin')
Vue.mixin(wxShareH5)



//是否是手机端
if (/Android|webOS|iPhone|iPod|iPad|BlackBerry/i.test(navigator.userAgent)) {

	//手机端
} else {
	// window.location.href = "/";
}




//调试
import VConsole from '@/components/vconsole/vconsole.min.js'
if (Vue.prototype.$util.getUrlQuery('test') == 1 || config.debug) {
	let vConsole = new VConsole();
}




// 注册全局组件
import tabBar from '@/components/tab-bar'
Vue.component('tab-bar', tabBar)
import myFab from '@/components/my-fab'
Vue.component('my-fab', myFab)
import GoodsPrice from '@/components/GoodsPrice'
Vue.component('goods-price', GoodsPrice)

// 注册全局过滤器
import * as filters from './filters'
Object.keys(filters).forEach(key => {
	Vue.filter(key, filters[key])
})

// 引入lodash
import _ from 'lodash'
Vue.prototype.$_ = _

import {
	router,
	RouterMount
} from './router.js' //路径换成自己的
Vue.use(router)

App.mpType = 'app'
const app = new Vue({
	store,
	...App
})


// http拦截器，将此部分放在new Vue()和app.$mount()之间，才能App.vue中正常使用
import httpInterceptor from '@/common/http.interceptor.js'
Vue.use(httpInterceptor, app)

// http接口API抽离，免于写url或者一些固定的参数
import httpApi from '@/common/http.api.js'
Vue.use(httpApi, app)


RouterMount(app, router, '#app')




