import store from '@/store/index.js'

//全局过滤器

//格式化日期
const formatTime = (time) => {
	let date = new Date(time * 1000)
	var year = date.getFullYear();
	var month = date.getMonth() + 1,
		month = month < 10 ? '0' + month : month;
	var day = date.getDate(),
		day = day < 10 ? '0' + day : day;

	return year + '-' + month + '-' + day;
}
//字符串变****
const encry = (str) => {
	//文字加密
	let arr = [...str]
	let n = arr.length
	let char = "*"
	let length = 4

	for (let i = 0; i <= n / 2; i++)
		arr[i] = char

	return arr.join("")
}
// 价格小数
const priceDecimal = (val) => {
	if (val !== parseInt(val))
		return val.split('.')[1];
	else
		return '00';
}
// 价格整数
const priceInt = (val) => {
	if (val !== parseInt(val))
		return val.split('.')[0];
	else
		return val;
}
const showPrice = (val) => {
	if (store.getters.isIosRecharge === true) {
		return '-'
	} else {
		return val
	}
}
export {
	formatTime,
	encry,
	priceDecimal,
	priceInt,
	showPrice
}