// 登录配置
import Vue from 'vue'
import _ from 'lodash'

const allowLoginTypes = [{
		key: 'mobile',
		label: '手机号登录'
	},
	{
		key: 'password',
		label: '账号密码登录'
	},
	{
		key: 'email',
		label: '邮箱登录'
	}
]

const getDefaultState = () => {
	return {
		icoimg: '',
		logo: '',
		openRegInputPid: false, // 注册填写推荐人ID
		openRegNeedPid: false, // 注册必填上级编号
		openRegTwoPassword: false, // 注册时登录密码二次确认
		openPayReg: false, //付费注册开关
		openRegInputMobile: false, //注册强制填写手机号
		loginConfigType: [], //前台支持注册/登录方式
		/* "mobile",手机号+验证码 登录、注册
		  "password",账号+密码 登录、注册
		  "email" 邮箱+验证码 登录、注册*/
		// wxLoginType: 2, //1=微信pc 2=微信二维码，
		loginList: [],

		currLoginType: '', //默认显示视图： password账号，mobile手机号，email邮箱
		loginTypeList: [],
		openWinType: '', // 弹框公告类型 user_login_open_window=用户登录页弹窗,user_reg_open_window=用户注册页弹窗,user_ucenter_open_window=用户中心弹窗




		agreeUser: false,

		session: '', //图形校验码

		// 2024-12-12 新增手机号国家码，背景图片
		mobileCodeOpen: false,
		h5LoginBgOpen: false,
		h5LoginBgImg: '',
		h5RegBgOpen: false,
		h5RegBgImg: '',
		// 2025-2-16 用户协议和隐私政策弹框
		showAgreePopup: false,
		isThirdLogin: false, //false:密码，邮箱，账号，true：三方登录
		retrievePasswordConfigType: [], // 找回密码方式：mobile手机号，email邮箱
	}
}

const state = getDefaultState()

const getters = {
	icoimg: (state) => state.icoimg,
	logo: (state) => state.logo,
	openRegInputPid: (state) => state.openRegInputPid,
	openRegNeedPid: (state) => state.openRegNeedPid,
	openRegTwoPassword: (state) => state.openRegTwoPassword,
	openPayReg: (state) => state.openPayReg,
	openRegInputMobile: (state) => state.openRegInputMobile,
	loginConfigType: (state) => state.loginConfigType,
	loginList: (state) => state.loginList,

	currLoginType: (state) => state.currLoginType,
	currLoginTypeName: (state) => {
		const find = allowLoginTypes.find(item => item.key == state.currLoginType)
		return find ? find.label : ''
	},
	loginTypeList: (state) => state.loginTypeList,
	openWinType: (state) => state.openWinType,
	agreeUser: (state) => state.agreeUser,

	mobileCodeOpen: state => state.mobileCodeOpen,
	h5LoginBgOpen: state => state.h5LoginBgOpen,
	h5LoginBgImg: state => state.h5LoginBgImg,
	h5RegBgOpen: state => state.h5RegBgOpen,
	h5RegBgImg: state => state.h5RegBgImg,

	showAgreePopup: state => state.showAgreePopup,
	isThirdLogin: state => state.isThirdLogin,

	retrievePasswordConfigType: state => state.retrievePasswordConfigType
}

const mutations = {
	setInitData: (state, payload) => {
		state.icoimg = payload.icoimg
		state.logo = payload.logo
		state.openRegInputPid = payload.open_reg_input_pid
		state.openRegNeedPid = payload.open_reg_need_pid
		state.openRegTwoPassword = payload.open_reg_two_password
		state.openPayReg = payload.open_pay_reg
		state.openRegInputMobile = payload.open_reg_input_mobile
		state.loginConfigType = payload.login_config_type
		state.loginList = payload.thirdLoginList

		state.mobileCodeOpen = payload.mobile_code_open
		state.h5LoginBgOpen = payload.h5_login_bg_open
		state.h5LoginBgImg = payload.h5_login_bg_img
		state.h5RegBgOpen = payload.h5_reg_bg_open
		state.h5RegBgImg = payload.h5_reg_bg_img
		state.retrievePasswordConfigType = payload.retrieve_password_config_type
	},
	setLoginTypeList(state, payload) {
		state.loginTypeList = payload
	},
	setCurrLoginType(state, payload) {
		state.currLoginType = payload
	},
	setOpenWinType(state, payload) {
		state.openWinType = payload
	},
	setAgreeUser(state, payload) {
		state.agreeUser = payload
	},
	setShowAgreePopup(state, payload) {
		state.showAgreePopup = payload
	},
	setIsThirdLogin(state, payload) {
		state.isThirdLogin = payload
	},
}

const actions = {
	async loadLoginConf({
		commit
	}) {
		const data = await Vue.prototype.$u.api.loginconfig({
			'pid': uni.getStorageSync('pid') || 0
		})
		commit('setInitData', data)
		uni.setStorageSync('open_reg_input_mobile', data.open_reg_input_mobile ? true : false)
		if (Array.isArray(data.login_config_type) && data.login_config_type.length) {
			const re = _.filter(allowLoginTypes, (item) => {
				return _.includes(data.login_config_type, item.key)
			})
			commit('setLoginTypeList', re)
			// if (re.length) {
			// 	commit('setCurrLoginType', re[0].key)
			// }
		}
		commit('setCurrLoginType', data.default_login_interface)
		return data
	}
}

export default {
	namespaced: true,
	state,
	mutations,
	actions,
	getters
}