/**
 * 页面返回
 * @param {Object} num 返回页面数量
 */
const back = (num = 1) => {
	if (getCurrentPages().length == 1) {
		on('/pages/index/index')
	} else {
		uni.navigateBack({
			delta: num
		});
	}
}
/**
 * 页面重定向返回
 * @param {Object} num 返回页面数量
 */
const redirect = (url) => {
	// tab页面
	let tabUrlArr = [
		'/pages/index/index',
		'/pages/msg/msg',
		'/pages/ucenter/index',
		'/pages/category/index',
		'/pages/cart/index',
	]
	let find = false
	tabUrlArr.forEach(tab_url => {
		if (startsWith(url, tab_url))
			find = true
	})

	if (find) {
		uni.switchTab({
			url
		})
	} else {
		uni.redirectTo({
			url: url
		})
	}
}
/**
 * 页面跳转
 * 
 * @param {Object} url 需要跳转的应用内非 tabBar 的页面的路径
 * @param {Object} animationType 窗口显示的动画效果
 * @param {Object} animationDuration 窗口动画持续时间，单位为 ms
 */
const to = (url, animationType = 'pop-in', animationDuration = 300) => {
	uni.navigateTo({
		url,
		animationType,
		animationDuration,
		success: function(res) {
			config.debug ? console.log(res) : '';
		},
		fail: function(e) {
			config.debug ? console.log(e) : '';
		}
	})
}
/**
 * 打开任意链接
 * @param {Object} url 页面地址
 */
const on = (url) => {
	url = decodeURIComponent(url);

	//外部地址
	if (/^(\/\/)+/.test(url)) {


		window.location.href = url





	} else if (/^(http|https):\/\/.+/.test(url)) {

		window.location.href = url





	} else {

		if (url.indexOf('/front/index/to_url') != -1) {
			window.location.href = window.location.protocol + "//" + window.location.host + url
			return
		}


		//内部地址		
		// tab页面
		let tabUrlArr = [
			'/pages/index/index',
			'/pages/msg/msg',
			'/pages/ucenter/index',
			'/pages/category/index',
			'/pages/cart/index',
		]
		// 判断内部地址是否存在参数，
		let idx = url.indexOf("?")
		if (idx != -1) {
			// tab页面传递的参数
			let params = getUrlParams(url)
			let path = url.substr(0, idx)
			// 判断页面是否是tab页面
			if (tabUrlArr.includes(path)) {
				uni.setStorageSync('tab-params', params)
				uni.switchTab({
					url: path
				})
			} else {
				to(url)
			}
		} else {
			if (tabUrlArr.includes(url)) {
				uni.switchTab({
					url: url
				})
			} else {
				to(url)
			}
		}
	}
}
//获取地址栏参数
const getUrlParams = (u) => {
	let url = ''
	if (u) {
		let idx = u.indexOf("?")
		if (idx > 0) {
			url = u.substr(idx)
		}
	} else {
		url = window.location.search //获取url中"?"符后的字串
	}
	let paramsObj = new Object();
	if (url.indexOf("?") != -1) {
		let str = url.substr(1);
		let strs = str.split("&");
		for (let i = 0; i < strs.length; i++) {

			paramsObj[strs[i].split("=")[0]] = decodeURI(strs[i].split("=")[1]);

		}
	}
	return paramsObj;
}
