const img = (url) => {
	let image = '';
	//当地址不存在
	if (url) {
		if ((/^data:image\//.test(url))) {
			image = url;
		} else if ((/^(http|https):\/\/.+/.test(url))) {
			image = url;
		} else if ((/^\/\/.+/.test(url))) {
			image = url;
		} else {
			image = config.cdnurl + url;
		}
	} else {
		image = config.cdnurl + '/statics/common/no_img.png';
	}
	return image;
}
