/**
 * 遍历树数据节点，查找符合条件的节点
 * @param {Array|Object} data 数据树，如 {id:1, children:[{id:2}]}
 * @param {Boolean} isFindOne 是否只找最先符合条件的一个
 * @param {Function} fn 查找回调函数，回调参数：item 节点，index节点当前兄弟节点中的索引，data 查找的数据树，函数返回true表示符合条件
 * @param {string} [field=children] 子级字段名称
 * @returns {Array|Object} 查找结果，isFindOne为true时返回Object， false时返回Array
 */

const traverse = (data = [], isFindOne, fn, field = 'children') => {
	let result = []
	data = Array.isArray(data) ? data : [data]
	for (let i = 0, len = data.length; i < len; i++) {
		const item = data[i]
		const checked = fn(item, i, data)
		const children = item[field]
		if (checked) {
			result.push(item)
			if (isFindOne) break
		}
		if (children) {
			const child = traverse(children, isFindOne, fn, field)
			if (child) result = result.concat(child)
		}
	}
	return isFindOne ? result[0] || null : result
}
// 通过id路径找到项
const findItemByIdPath = (treeData, idPath = []) => {
	if (!Array.isArray(idPath) || idPath.length === 0) {
		return null;
	}

	function findItem(nodes, id) {
		for (let i = 0; i < nodes.length; i++) {
			if (nodes[i].id == id) {
				return nodes[i];
			}
			if (nodes[i].children) {
				const found = findItem(nodes[i].children, id);
				if (found) return found;
			}
		}
		return null;
	}
	return findItem(treeData, idPath[0]) ? findItem(treeData, idPath[0]).children && idPath.length > 1 ?
		findItemByIdPath(findItem(treeData, idPath[0]).children, idPath.slice(1)) : findItem(treeData, idPath[0]) :
		null;
}

const exchangeArray = (beforeIdx, newIdx, array = [], isDeep = false) => {
	const newArray = isDeep ? clone(array) : array
	if (beforeIdx > -1 && newIdx > -1) {
		// 先替换后面的，然后拿到替换的结果替换前面的
		newArray.splice(beforeIdx, 1, newArray.splice(newIdx, 1, newArray[beforeIdx]).pop())
	}
	return newArray
}

const initCategoryData = (nodes, path, result = []) => {
	const id = path.shift()
	if (id) {
		const node = nodes.find(item => item.id == id)
		if (node.id == id) {
			result.push(node)

			if (node.children) {
				initCategoryData(node.children, path, result)
			}
		} else {
			if (node.children) {
				initCategoryData(node.children, path, result)
			}
		}
	} else {
		if (nodes.length) {
			result.push(nodes[0])
			if (nodes[0].children) {
				initCategoryData(nodes[0].children, path, result)
			}
		}
	}

	return result
}

const changeURLArg = (arg, arg_val, url = null, replace = true) => {
	if (url == null) {
		url = location.href
	}
	var new_url = url
	var pattern = arg + '=([^&]*)'
	var replaceText = arg + '=' + arg_val
	if (url.match(pattern)) {
		var tmp = '/(' + arg + '=)([^&]*)/gi'
		new_url = url.replace(eval(tmp), replaceText)
	} else {
		if (url.match('[?]')) {
			new_url = url + '&' + replaceText
		} else {
			new_url = url + '?' + replaceText
		}
	}

	if (replace) {
		if (window.history && history.pushState) {
			history.replaceState(null, '', new_url)
		}
	} else {
		return new_url
	}
}

const getShareLink = (params) => {
	// 获取当前页面的实例
	const pages = getCurrentPages();
	const currentPage = pages[pages.length - 1];

	// 构建分享的页面路径
	const url = currentPage.route;

	// 如果需要传递参数
	const options = {
		...currentPage.options,
		...params
	};
	let query = '?';
	for (let key in options) {
		if (options.hasOwnProperty(key)) {
			query += `${key}=${options[key]}&`;
		}
	}
	query = query.substring(0, query.length - 1); // 移除最后一个"&"

	return url + query;
}
const getShareLink2 = (params) => {
	let {
		origin,
		pathname,
		searchParams
	} = new URL(location.href)
	const url_params = {}
	searchParams.forEach((v, k) => {
		url_params[k] = v
	})
	if (params) {
		_.merge(url_params, params)
	}

	const options = []
	for (let key in url_params) {
		if (url_params[key] !== undefined)
			options.push(`${key}=${url_params[key]}`)
	}

	if (options.length) {
		let set = new Set(options)
		return origin + pathname + '?' + [...set].join('&')
	} else {
		return origin + pathname
	}
}

