import {
	mapState
} from 'vuex'
import store from "@/store"

// 尝试将用户在根目录中的store/index.js的vuex的state变量，全部加载到全局变量中
let $uStoreKey = [];
try {
	$uStoreKey = store.state ? Object.keys(store.state) : [];
} catch (e) {

}

module.exports = {
	options: {
		styleIsolation: 'shared'
	},
	beforeCreate() {
		// 将vuex方法挂在到$u中
		// 使用方法为：如果要修改vuex的state中的user.name变量为"史诗" => this.$u.vuex('user.name', '史诗')
		// 如果要修改vuex的state的version变量为1.0.1 => this.$u.vuex('version', '1.0.1')
		this.$u.vuex = (name, value) => {
			store.commit('$uStore', {
				name,
				value
			})
		}
	},
	onReady() {
		let T = this
		uni.getSystemInfo({
			success(res) {
				T.windowHeight = res.windowHeight
			}
		})
	},
	onShow() {
		if (this.__page__) {
			if (this.token) {
				const res = this.checkUserInfo()
				const path_list = [`/pages/ucenter_sub/certify/index`]
				if (path_list.includes(this.$Route.path))
					return

				if (res.success === false) {
					if (res.route != this.$Route.path) {
						this.$nextTick(() => {
							this.$util.msg(res.msg)
							setTimeout(() => {
								this.$Router.push({
									path: res.route
								})
							}, 1000)
						})
					}
				}
			}
		}
	},
	computed: {
		// 将vuex的state中的所有变量，解构到全局混入的mixin中
		...mapState($uStoreKey)
	},
	methods: {
		// 判断绑定邮箱，手机号码，实名认证
		checkUserInfo() {
			const res = {
				success: true,
				route: '',
				msg: ''
			}
			if (this.userinfo.need_bind_email === true) {
				res.success = false
				res.route = '/pages/ucenter_sub/set'
				res.msg = "请先绑定邮箱"
			} else if (this.userinfo.need_bind_mobile === true) {
				res.success = false
				res.route = `/pages/ucenter_sub/set`
				res.msg = "请先绑定手机号码"
			} else if (this.userinfo.need_bind_idcard === true) {
				res.success = false
				res.route = `/pages/ucenter_sub/set`
				res.msg = "请先实名认证"
			}

			return res
		},
		//商品详情
		onGoods(id, type, option) {
			// console.log(this.$u.vuex('sysconfig'));
			if (!type) type = 1

			let kss_lifeData = uni.getStorageSync('kss_lifeData')
			let page_index = 0;

			if (kss_lifeData && kss_lifeData.sysconfig && kss_lifeData.sysconfig.pages) {
				page_index = kss_lifeData.sysconfig.pages[type].v
			}

			//优先级最高
			if (option && option.dyr_type == 1) {
				page_index = 1
			}

			if (option && option.goods_url_type && option.goods_url_type == 1 && option.goods_url) {
				this.$util.on(option.goods_url);
				return;
			}



			switch (type) {
				case 1: //点击商品

					if (page_index == 1) {
						this.$util.on(`/pages/goods/detail?id=${id}`)
					} else {
						this.$util.on(`/pages/category/goodslist?id=${id}`)
					}

					break;
				case 2: //点击分类

					if (page_index == 1) {
						this.$util.on(`/pages/category/index1?cid=${id}`)
					} else {
						this.$util.on(`/pages/category/goodslist?cid=${id}`)
					}
					break;
				default:
					this.$util.on(`/pages/category/goodslist?id=${id}`)
					break;

			}
		},
		preview(url) {
			uni.previewImage({
				urls: [url],
				current: url,
			})
		},
	}
}