<template>
	<uni-fab v-if="fabIndex ==0" ref="fab" :pattern="pattern" :content="fabContent" horizontal="right" vertical="bottom"
		direction="horizontal" @trigger="trigger"></uni-fab>

	<uni-fab v-else-if="fabIndex ==1" ref="fab" :pattern="pattern"  :content="fabContent" :rightBottom="10" horizontal="right" vertical="bottom"
		direction="horizontal" @trigger="trigger"></uni-fab>
</template>

<script>
	export default {
		name: "my-fab",
		props: {
			fabIndex: {
				type: Number,
				default: 0,
			}
		},
		data() {
			return {
				pattern: {
					color: '#7A7E83',
					backgroundColor: '#fe8956',
					selectedColor: '#007AFF',
					buttonColor: '#fe8956',
					iconColor: '#fff',
				},
				fabContent: [{
						iconPath: this.$util.img('/statics/uni/img/fab/home.png') ,
						url: '/pages/index/index'
					}, {
						iconPath: this.$util.img('/statics/uni/img/fab/order.png') ,
						url: '/pages/buyer/order'
					},
					{
						iconPath: this.$util.img('/statics/uni/img/fab/user.png'),
						url: '/pages/ucenter/index'
					}
				]
			};
		},
		methods: {
			trigger(e) {
				this.$refs['fab'].close()
				this.$util.on(e.item.url)
			},
		}
	}
</script>

