<template><App :keepAliveInclude="keepAliveInclude"/></template><script>
	// import getPages from './pages.js'
	import Vue from 'vue'
	import {
		mapActions,
		mapMutations,
		mapGetters
	} from 'vuex'
	import config from '@/common/config.js'

	export default {
		computed: {
			...mapGetters(['sysconfig', 'token', 'userinfo'])
		},
		onLaunch: async function(e) {
			await this.loadSystemConfig()
			// 隐藏uni原生tabbar
			uni.hideTabBar()
			//#ifdef APP
			plus.screen.lockOrientation("portrait-primary")
			//#endif

			//上级ID
			if (e.query.pid) {
				uni.setStorageSync('pid', e.query.pid)
			}
			// 获取运行设备信息
			await this.setDeviceInfo(this.$util.sys())
			// 检查token有效性
			this.checkToken()

			// #ifdef MP
			// 判断小程序版本
			this.checkUpdateVersion()
			// #endif

			// 获取系统配置
			// #ifdef H5
			await this.setSysConfig()
			// 判断自动登录
			if (this.checkAutoLogin()) {
				this.doAutoLogin()
				return
			}
			// #endif
		},
		onShow: function() {

		},
		onHide: function() {
			console.log('App Hide')
		},
		onError: function(e) {
			console.log(e)
		},
		onPageNotFound() {
			// #ifdef H5
			location.href = '/';
			// #endif
		},

		methods: {
			...mapActions(['setSystemConfig', 'setDeviceInfo', 'logout']),
			...mapMutations(['updateUserInfo']),
			async loadSystemConfig() {
				const systemConfigRes = await this.$u.api.sysConfig()
				// console.log(systemConfigRes);
				let default_search_time =	7
				if(systemConfigRes.addon && systemConfigRes.addon.default_search_time ){
					default_search_time = systemConfigRes.addon.default_search_time
				}
				uni.setStorageSync('default_search_time', default_search_time)


				await this.setSystemConfig(systemConfigRes)
				if (this.$Route.path == '/pages/index/index') {
					this.$util.setNavigationBarTitle()
				}
			},
			async setSysConfig() {
				//首次启动加载配置
				const res = this.sysconfig
				// #ifdef H5
				const favicon = document.querySelector('link[rel="icon"]')
				if (favicon) {
					favicon.href = res.icoimg
				} else {
					const link = document.createElement('link')
					link.rel = 'icon'
					link.href = res.icoimg

					document.head.appendChild(link)
				}
				// 修改网页meta元数据
				const {
					basic_keyword,
					basic_system_description,
				} = res
				let head = document.getElementsByTagName('head')
				if (!head[0].getElementsByTagName('meta').keywords) {
					let meta = document.createElement('meta')
					meta.name = "keywords"
					meta.content = basic_keyword
					head[0].appendChild(meta)
				} else {
					head[0].getElementsByTagName('meta').keywords.content = basic_keyword
				}
				if (!head[0].getElementsByTagName('meta').description) {
					let meta2 = document.createElement('meta')
					meta2.name = "description"
					meta2.content = basic_system_description
					head[0].appendChild(meta2)
				} else {
					head[0].getElementsByTagName('meta').description.content = basic_system_description
				}

				// #endif

				if (res.basic_in_js) {
					this.getHtml(res.basic_in_js)
				}
			},
			async getHtml(res) {
				const loadJs = (tagAttrs) => {
					return new Promise((resolve, reject) => {
						const script = document.createElement('script')
						script.type = 'text/javascript'
						for (let o in tagAttrs) {
							script.setAttribute(o, tagAttrs[o])
						}
						script.onload = () => {
							resolve(script)
						}
						script.onerror = (err) => {
							reject(err)
						}
						document.body.append(script)
					})
				}
				// 正则获取标签所有属性
				const getAllAttr = (str) => {
					// /\s*[^=\s+]+\s*=\s*([^=>]+)?(?=(\s+|>))/igm
					let arr = str.match(/(\s+\w+(=["'][^"']*["'])?)/gi).map(item => unescape(item))
					// console.log(arr)
					let re = {}
					arr.forEach(item => {
						// 去除空格和双引号，单引号
						item = item.replace(/\s*/g, "").replace(/"/g, "").replace(/’/g, "")
						let first_index = item.indexOf('=')
						re[item.substring(0, first_index)] = item.substring(first_index + 1)
					})
					// console.log(re)
					return re
				}

				var scripts = document.createElement('div');
				// script标签中间的内容
				this.$nextTick(() => {
					scripts.innerHTML = res.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
					document.body.appendChild(scripts);
				});
				// script标签中src处理
				var reg = /<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi
				var result = res.match(reg)
				let scriptText = []
				let scriptList = []
				result.forEach((item) => {
					if (item.indexOf('src=') != -1) {
						// var reg3 = /<script.*?src="(.*?)".*?\/?>/i						
						// const url = item.match(reg3)[1]
						scriptList.push(getAllAttr(item))
					} else {
						var reg2 = /<script>([\s\S]*?)<\/script>/
						let script = document.createElement('script')
						scriptText.push(item.match(reg2)[1])
					}
				})
				const list = scriptList.map((item) => {
					return loadJs(item)
				})
				//解决script标签内写入的js依赖src引入的js文件的问题				
				Promise.all(list).then((values) => {
					scriptText.forEach((text) => {
						let script = document.createElement('script')
						script.type = 'text/javascript'
						script.text = text
						document.getElementsByTagName('body')[0].appendChild(script)
					})
				})
			},
			async checkToken() {
				if (this.token) {
					const {
						status
					} = await Vue.prototype.$u.api.valiToken({
						token: this.token
					})
					if (status != 1) {
						await this.logout()
					} else {
						const res = await this.$u.api.userinfo()
						let userinfo = res.userinfo
						userinfo.isLogin = true
						this.updateUserInfo(userinfo)
					}
				}
			},
			checkAutoLogin() {
				let open_auto_login_user = this.$_.get(this.sysconfig, 'addon.open_auto_login_user')
				let except_pages = ['/pages/user/thirdlogin', '/pages/common/topay']

				// console.log(this.$Route.path);
				if (open_auto_login_user && !this.token && !except_pages.includes(this.$Route.path)) {
					let browser_type = this.$util.browserType()
					if (browser_type.weixin) {
						return true
					} else {
						return false
					}
				} else {
					return false
				}
			},
			async doAutoLogin() {
				const pid = uni.getStorageSync('pid')
				const autoLoginRes = await this.$u.api.getWxgzhLoginUrl({
					pid: pid,
					uri: config.apiurl + this.$Route.path,
					type: 2
				})
				window.location.href = autoLoginRes.url
			},
			/**
			 * 检测当前的小程序
			 * 是否是最新版本，是否需要下载、更新
			 */
			checkUpdateVersion() {
				//判断微信版本是否 兼容小程序更新机制API的使用
				if (wx.canIUse('getUpdateManager')) {
					const updateManager = wx.getUpdateManager();
					//检测版本更新
					updateManager.onCheckForUpdate(function(res) {
						if (res.hasUpdate) {
							updateManager.onUpdateReady(function() {
								wx.showModal({
									title: '温馨提示',
									content: '检测到新版本，是否重启小程序？',
									showCancel: false,
									success: function(res) {
										if (res.confirm) {
											// 新的版本已经下载好，调用 applyUpdate 应用新版本并重启
											updateManager.applyUpdate()
										}
									}
								})
							})
							updateManager.onUpdateFailed(function() {
								// 新版本下载失败
								wx.showModal({
									title: '已有新版本',
									content: '请您删除小程序，重新搜索进入',
								})
							})
						}
					})
				} else {
					wx.showModal({
						title: '溫馨提示',
						content: '当前微信版本过低，无法使用该功能，请升级到最新微信版本后重试。'
					})
				}
			},
		}
	}
</script>

<style lang="scss">
	@import "uview-ui/index.scss";
	/*每个页面公共css */
	@import "/static/css/iconfont/iconfont.css";
	@import '/static/css/fonnie.css';
	@import '/static/css/style.css';
</style>