import Vue from 'vue'

export const wxH5share = async (options) => {
	const res = await Vue.prototype.$u.api.sharewxgzhConfig({
		linkUrl: options.url
	})
	// console.log(res)

	const jweixin = Vue.prototype.$wx
	// console.log(res)	
	jweixin.config({
		debug: res.debug, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
		// debug:true,
		appId: res.appId, // 必填，公众号的唯一标识
		timestamp: res.timestamp, // 必填，生成签名的时间戳
		nonceStr: res.nonceStr, // 必填，生成签名的随机串
		signature: res.signature, // 必填，签名，见附录1
		// surl: res.url, //自己添加的，debug为true的时候可以网页打印出对应的URL是否正确
		jsApiList: res
			.jsApiList //['updateAppMessageShareData', 'updateTimelineShareData', 'openLocation']
	})
	setTimeout(() => {
		jweixin.ready(() => {
			//自定义“分享给朋友”及“分享到QQ”按钮的分享内容（1.4.0）
			jweixin.updateAppMessageShareData({
				title: options.share_data.title || '分享标题', // 分享标题
				desc: options.share_data.desc || '', // 分享描述
				// link: options.share_data.link, // 分享链接
				link: options.link,
				imgUrl: options.share_data.imgUrl || '', // 分享图标
				success: res => {

				},
				cancel: function() {
					// 用户取消分享后执行的回调函数
				}
			})
			//自定义“分享到朋友圈”及“分享到QQ空间”按钮的分享内容（1.4.0）
			jweixin.updateTimelineShareData({
				title: options.share_data.title || '分享标题', // 分享标题
				// link: options.share_data.link, // 分享链接
				link: options.link,
				imgUrl: options.share_data.imgUrl || '', // 分享图标
				success: res => {

				},
				cancel: function() {
					// 用户取消分享后执行的回调函数
				}
			})
			jweixin.onMenuShareAppMessage({
				title: options.share_data.title || '分享标题', // 分享标题
				desc: options.share_data.desc, // 分享链接
				// link: options.share_data.link, // 分享链接
				link: options.link,
				imgUrl: options.share_data.imgUrl || '', // 分享图标
				success: function(res) {

				},
				cancel: function(res) {

				}
			})
		})
	}, 500)
}