// 这里的vm，就是我们在vue文件里面的this，所以我们能在这里获取vuex的变量，比如存放在里面的token
// 同时，我们也可以在此使用getApp().globalData，如果你把token放在getApp().globalData的话，也是可以使用的
// import md5Libs from "uview-ui/libs/function/md5";
import config from "@/common/config";
import store from '@/store'

const install = (Vue, vm) => {
	Vue.prototype.$u.http.setConfig({

		baseUrl: config.apiurl,

		// 如果将此值设置为true，拦截回调中将会返回服务端返回的所有数据response，而不是response.data
		// 设置为true后，就需要在this.$u.http.interceptor.response进行多一次的判断，请打印查看具体值
		originalData: true,
		// 设置自定义头部content-type
		header: {
			'content-type': 'application/json',

			'Form-Where': navigator.userAgent.toLowerCase().indexOf("micromessenger") !== -1 ? 'wechat' :
				'h5',







		},
	});
	// 请求拦截，配置Token等参数
	Vue.prototype.$u.http.interceptor.request = (config) => {
		let token = uni.getStorageSync('token');
		if (token) {
			config.header.authorization = 'Bearer ' + uni.getStorageSync('token');
		}

		// let time = Math.round(new Date() / 1000).toString();
		// config.header.sign = md5Libs.md5(md5Libs.md5('zmqfonnie') + time) + time;


		config.header.sign = Vue.prototype.$util.reqSign()
		// 方式一，存放在vuex的token，假设使用了uView封装的vuex方式，见：https://uviewui.com/components/globalVariable.html
		// config.header.token = vm.token;

		// 方式二，如果没有使用uView封装的vuex方法，那么需要使用$store.state获取
		// config.header.token = vm.$store.state.token;

		// 方式三，如果token放在了globalData，通过getApp().globalData获取
		// config.header.token = getApp().globalData.username;

		// 方式四，如果token放在了Storage本地存储中，拦截是每次请求都执行的，所以哪怕您重新登录修改了Storage，下一次的请求将会是最新值
		// const token = uni.getStorageSync('token');
		// config.header.token = token;

		// console.log(config)
		return config;
	}
	// 响应拦截，判断状态码是否通过
	Vue.prototype.$u.http.interceptor.response = (res) => {
		// 如果把originalData设置为了true，这里得到将会是服务器返回的所有的原始数据
		// 判断可能变成了res.statusCode，或者res.data.code之类的，请打印查看结果

		if (res.statusCode == 200) {
			try {

				if (res.data.is_gzde) {
					res.data.data = Vue.prototype.$util.decodeData(res.data.data)
				}

				if (res.data.code == 200) {
					// 如果把originalData设置为了true，这里return回什么，this.$u.post的then回调中就会得到什么

					// config.debug && console.log(res.data.data)
					return res.data.data;
				} else if (res.data.code == 400) {
					// uni.showToast({
					// 	title: res.data.msg,
					// 	duration: 2000,
					// 	icon: 'none',
					// });
					Vue.prototype.$util.msg(res.data.msg)
					switch (res.data.msg) {
						case '请绑定邮箱后下单':
							// case '请绑定手机后下单':
						case '请实名认证后下单':
							setTimeout(function() {
								Vue.prototype.$util.on('/pages/ucenter_sub/set')
							}, 200)
							break;
					}


					return false;
				} else if (res.data.code == 2) {
					// uni.showToast({
					// 	title: res.data.msg,
					// 	duration: 2000,
					// 	icon: 'none',
					// });

					// console.log(res.data.msg);
					Vue.prototype.$util.msg(res.data.msg)
					let url = ''
					let wait = 1800

					if (res.data.data) {
						if (res.data.data.url) {
							url = res.data.data.url
						}
						if (res.data.data.wait) {
							wait = res.data.data.wait
						}
					}

					setTimeout(function() {
						if (url) {
							Vue.prototype.$util.on(url)
						} else {
							Vue.prototype.$util.back()
						}
					}, wait)

					return false;
				} else if (res.data.code == 410000) {
					// uni.showToast({
					// 	title: res.data.msg,
					// 	duration: 2000,
					// 	icon: 'none',
					// });

					// console.log(Vue.prototype.$u);
					// Vue.prototype.$util.vuex().commit('logout')
					Vue.prototype.$util.msg(res.data.msg)


					store.commit('logout')

					Vue.prototype.$u.vuex('userinfo.token', '');
					Vue.prototype.$u.vuex('userinfo.id', 0);
					Vue.prototype.$u.vuex('userinfo.isLogin', false);


					// setTimeout(() => {
					// 	uni.removeStorageSync('callback_url')
					// 	Vue.prototype.$util.on('/pages/user/login')
					// }, 2000)

					//从哪进登录后就跳到哪
					let routes = getCurrentPages()
					let {
						route,
						options
					} = routes[routes.length - 1]
					let redirect = Vue.prototype.$util.getRedirectUrl(route, options)


					setTimeout(function() {
						Vue.prototype.$util.on('/pages/user/login?redirect=/' + redirect)
					}, 2000)








					return false;
				} else {
					uni.showToast({
						title: `错误码${res.code},${res.msg}`,
						duration: 2000,
						icon: 'none',
					});
					return false;
				}
			} catch (res) {
				uni.showToast({
					title: '调试中(⊙o⊙)!',
					duration: 2000,
					icon: 'none',
				});
				return false;
			}

		} else {
			// uni.showToast({
			// 	title: '压力有点大,请稍后再试!',
			// 	duration: 2000,
			// 	icon: 'none',
			// });
			return false;
		}
	}

}
export default {
	install
}