<template>
	<u-tabbar :before-switch="beforeSwitch" :height="height" :active-color='activeColor' :inactive-color="inactiveColor"
		:list="tabBarList"></u-tabbar>
</template>

<script>
	import {
		mapActions,mapGetters
	} from 'vuex'
	export default {
		name: "tab-bar",
		props: {
			height: {
				type: Number,
				default: 110
			},
			activeColor: {
				type: String,
				default: '#f06c7a'
			},
			inactiveColor: {
				type: String,
				default: '#606266'
			},
		},
		data() {
			return {
				isGoTop: false,
			};
		},
		computed:{
			...mapGetters(['deviceInfo'])
		},
		mounted() {
			uni.$on('onPageScroll', (scrollTop) => {				
				if (scrollTop > this.deviceInfo.height) {
					this.setGoTop()
					this.isGoTop = true
				} else {
					this.removeGoTop()
					this.isGoTop = false
				}
			})
		},
		destroyed() {
			uni.$off('onPageScroll')
		},
		methods: {
			...mapActions(['setGoTop', 'removeGoTop']),
			beforeSwitch(res) {	
				console.log(this)
				if (res == 0)
				{
					if(this.isGoTop)
					{
						this.$emit('go-top')
					}
				}
				else
				{
					if(this.isGoTop)
						this.removeGoTop()
				}
				return true
			}
		}
	}
</script>

<style lang="scss" scoped>
::v-deep{
	.u-tabbar__content__item__button{
		top: 16rpx;
	}
	.u-tabbar__content__item__text{
		bottom: 18rpx;
	}
}
</style>