// 关键字搜索
import Vue from 'vue'
import _ from 'lodash'

const cacheKey = 'search-history'
const cacheData = uni.getStorageSync(cacheKey)
const saveCacheData = function(key, value) {
	let tmp = uni.getStorageSync(cacheKey)
	tmp = tmp ? tmp : {}
	_.set(tmp, key, value)
	uni.setStorageSync(cacheKey, tmp)
}

const getDefaultState = () => {
	return {
		// ------不需要存入缓存数据--------------
		max: 20, // 最大缓存个数
		// ------需要存入缓存数据-------
		keywords: cacheData.keywords || [], //关键字列表,目前仅支持文本，'张三'
	}
}
const state = getDefaultState()
const getters = {
	keywords: state => state.keywords,
}
const mutations = {
	addKeyWord: (state, payload) => {
		if (_.includes(state.keywords, payload)) {
			return
		}
		const keywords = [...state.keywords]
		if (keywords.length > state.max) {
			keywords.splice(0, 1)
		}
		state.keywords = _.concat(keywords, payload)
		saveCacheData('keywords', state.keywords)
	},
	clearHistory: (state, payload) => {
		state.keywords = []
		saveCacheData('keywords', state.keywords)
	}
}
const actions = {

}

export default {
	namespaced: true,
	state,
	mutations,
	actions,
	getters
}