<template>
	<view class="split-price">
		<view class="symbol">￥</view>
		<view class="integer">{{ part1 }}</view>
		<view class="decimals">.{{part2}}</view>
	</view>
</template>

<script>
	export default {
		name: 'GoodsPrice',
		components: {

		},
		props: {
			price: {
				type: [Number, String],
				default: 0
			}
		},
		data() {
			return {
				part1: '0',
				part2: '0'
			}
		},
		watch: {
			price: {
				handler(nv) {
					let arr = nv.toString().split('.')
					if (arr.length == 1) {
						this.part1 = arr[0]
						this.part2 = '00'
					} else if (arr.length == 2) {
						this.part1 = arr[0]
						this.part2 = arr[1]
					}
				},
				immediate: true,
			}
		},
		mounted() {

		}
	}
</script>

<style scoped lang="scss" scoped>
	.split-price {
		display: flex;
		align-items: baseline;
		color: rgb(255, 44, 60);

		.symbol {
			font-size: 26rpx;
		}

		.integer {
			font-size: 34rpx;
			font-weight: 500;
		}

		.decimals {
			font-size: 26rpx;
		}
	}
</style>