import Vue from 'vue'
import Vuex from 'vuex'
Vue.use(Vuex)

import modules from "./modules";

let lifeData = {};

try {
	// 尝试获取本地是否存在lifeData变量，第一次启动APP时是不存在的
	lifeData = uni.getStorageSync('kss_lifeData');
	lifeData.token = uni.getStorageSync('token') || ''
} catch (e) {

}

// 需要永久存储，且下次APP启动需要取出的，在state中的变量名
let saveStateKeys = ['userinfo', 'sysconfig', 'goodsCateListType', 'token', 'deviceInfo', 'whitePageList'];

// 保存变量到本地存储中
const saveLifeData = function(key, value) {

	// 判断变量名是否在需要存储的数组中
	if (saveStateKeys.indexOf(key) != -1) {
		// 获取本地存储的lifeData对象，将变量添加到对象中
		let tmp = uni.getStorageSync('kss_lifeData');
		// 第一次打开APP，不存在lifeData变量，故放一个{}空对象
		tmp = tmp ? tmp : {};
		tmp[key] = value;
		// 执行这一步后，所有需要存储的变量，都挂载在本地的lifeData对象中
		uni.setStorageSync('kss_lifeData', tmp);
	}
}
var userinfo = {
	id: 0,
	company: '用户',
	username: '未登录',
	headurl_img: "/statics/uni/img/user/logo.png",
	balance: '0.00',
	commission_money: '0.00',
	mobile: '',
	level_id: 0,
	level_name: '无等级',
	qq: '',
	isLogin: false,
	wxgzh_openid: '',
	wxxcx_openid: '',
	is_team_head: 0,
	email: "",
	status: 0,
	reg_time: "",
	trade_password_open: 0,
	has_trade_password: true,
	max_level: 0,
	level_img: "",
	default_level: 0,
	is_renew: false,
	expire_time: ''
};

// 默认设备信息结构
const deviceInfo = {
	height: 0,
	model: "",
	platform: "",
	screenHeight: 0,
	top: 0,
	windowBottom: 0,
	windowHeight: 0,
}
// 默认游客访问的路由
const whitePageList = [
	'/',
	'/pages/index/index',
	'/pages/category/index',
	'/pages/msg/msg',
	'/pages/cart/index',
	'/pages/ucenter/index',


	'/pages/user/login',
	'/pages/user/thirdlogin', //登录
	'/pages/user/login',
	'/pages/user/reg',
	'/pages/user/resetpsw',

	'/pages/category_sub/goodslist',
	'/pages/category_sub/index1',

	'/pages/common/topay', //支付
	'/pages/common/parse',
	'/pages/common/poster',
	'/pages/common/webview',

	'/pages/index_sub/billboard',
	'/pages/index_sub/food',
	'/pages/index_sub/kefu',
	'/pages/index_sub/pricelog',

	'/pages/msg_sub/msgDetail',
	'/pages/msg_sub/msgList',


	'/pages/goods/detail',
	'/pages/goods/list',

	'/pages/news/adjust_price/index',

	'/pages/search/search',
	'/pages/search/searchList',


	'/pages/index/test',
	'/pages/special/index', //diy页面
	'/pages/recharge/recharge', //快速充值

	'/pages/404/404'
]
const indexData = {
	cartNum: 0, //购物车里的商品数量
	pid: 0 //推广人uid
}
// diy缓存页面栈
const diyPageStack = {
	maxLen: 5,
	list: [],
}
// diy缓存页面列表
const diyPageList = [
	'/pages/index/index',
	'/pages/ucenter/index',
	'/pages/goods/detail',
	'/pages/goods/list',
	'/pages/category/index'
]
// diy页面默认配色方案
const defaultTheme = {
	bntColor: "red",
	gradient: "red",
	minorColor: "red",
	minorColorT: "red",
	priceColor: "red",
	theme: "#333"
}

const store = new Vuex.Store({
	state: {
		// 如果上面从本地获取的lifeData对象下有对应的属性，就赋值给state中对应的变量
		// 加上vuex_前缀，是防止变量名冲突，也让人一目了然
		userinfo: lifeData.userinfo ? lifeData.userinfo : userinfo,
		//系统配置
		sysconfig: {
			logo: '',
			icoimg: '',
			pageindex: 0, //首页模板
			company_type: 0, //商品是否显示实际库存 0显示充足
			basic_system_name: '',
			basic_system_short_name: '',
			gzhimg: '',
			wap_front_skin: 0,
			pages: {
				cate_list: 0,
				goods_detail: 0,
			},
			goods: {
				default_goods_img: '',
				default_warn_stock_num: 0,
				goods_cate_list_type: 0,
				goods_sale_show: true,
				goods_uid_type_show: true,
				h5_cate_cen: 0, // H5分类页层级
				view_min_goods_price: false,
			},
			login_menu: {
				"is_login_category_goodslist": 1,
				"is_login_goods_price_log": 1,
				"is_login_goods_detail": 1,
				"site_in_page_choose": "0",
				"site_default_in_page": "",
			},
			addon: {
				goodsentity: true,
				// categoryrecharge: false,
			},
		},




		tabBarList: [{
				iconPath: "/template/h5/diy/static/img/tabbar/home.png",
				selectedIconPath: "/template/h5/diy/static/img/tabbar/home-on.png",
				text: '首页',
				count: 0,
				isDot: false,
				customIcon: false,
				pagePath: "/pages/index/index",
			},
			{
				iconPath: "/template/h5/diy/static/img/tabbar/category.png",
				selectedIconPath: "/template/h5/diy/static/img/tabbar/category-on.png",
				text: '分类',
				customIcon: false,
				pagePath: "/pages/category/index",
			},
			{
				iconPath: "/template/h5/diy/static/img/tabbar/msg.png",
				selectedIconPath: "/template/h5/diy/static/img/tabbar/msg-on.png",
				text: '消息',
				customIcon: false,
				pagePath: "/pages/msg/msg",
			},
			{
				iconPath: "/template/h5/diy/static/img/tabbar/user.png",
				selectedIconPath: "/template/h5/diy/static/img/tabbar/user-on.png",
				text: '我的',
				count: 0,
				isDot: false,
				customIcon: false,
				pagePath: "/pages/ucenter/index",
			}
		],





































		goodsCateListType: lifeData.goodsCateListType ? lifeData.goodsCateListType : 0,
		token: lifeData.token ? lifeData.token : '',
		deviceInfo,
		whitePageList,
		indexData,
		diyPageStack,
		diyPageList,
		defaultTheme,
		currentTheme: "", // diy页面当前主题色
		cartGoodsNum: 0, // 购物车商品数量
		cartAmountMoney: 0, // 购物车总计金额
		cartGoodsIds: [], // 购物车ids
	},
	mutations: {
		$uStore(state, payload) {
			// console.log(state,payload);
			// 判断是否多层级调用，state中为对象存在的情况，诸如user.info.score = 1
			let nameArr = payload.name.split('.');
			let saveKey = '';
			let len = nameArr.length;
			if (len >= 2) {
				let obj = state[nameArr[0]];
				for (let i = 1; i < len - 1; i++) {
					obj = obj[nameArr[i]];
				}
				obj[nameArr[len - 1]] = payload.value;
				saveKey = nameArr[0];
			} else {
				// 单层级变量，在state就是一个普通变量的情况
				state[payload.name] = payload.value;
				saveKey = payload.name;
			}
			// 保存变量到本地，见顶部函数定义
			saveLifeData(saveKey, state[saveKey])
		},
		logout(state, payload) {
			//清除token
			uni.removeStorageSync('token')
			this.commit('$uStore', {
				name: 'token',
				value: ''
			})
			this.commit('$uStore', {
				name: 'userinfo',
				value: userinfo
			})
		},
		setWhitePageList(state, payload) {
			this.commit('$uStore', {
				name: 'whitePageList',
				value: payload
			})
		},
		setPid(state, payload) {
			this.commit('$uStore', {
				name: 'indexData.pid',
				value: payload
			})
		},
		// 添加diy数据
		addDiyData(state, payload) {
			const {
				path,
				diyData
			} = payload
			let copy_list = Vue.prototype.$_.cloneDeep(state.diyPageStack.list)
			let index = copy_list.findIndex(item => item.path === path)
			if (index != -1) {
				copy_list.splice(index, 1)
				copy_list.push({
					path,
					diyData
				})
			} else {
				if (state.diyPageStack.list.length < state.diyPageStack.maxLen) {
					copy_list.push({
						path,
						diyData
					})
				} else {
					copy_list.shift()
					copy_list.push({
						path,
						diyData
					})
				}
			}
			state.diyPageStack.list = copy_list
		},
		// 更新diy数据
		updateDiyData(state, payload) {
			const {
				path,
				data: {
					key,
					value
				}
			} = payload
			let copy_list = Vue.prototype.$_.cloneDeep(state.diyPageStack.list)
			let index = copy_list.findIndex(item => item.path === path)
			if (index != -1) {
				copy_list[index][key] = value
				state.diyPageStack.list = copy_list
			} else
				return false
		},
		// 更新用户信息
		updateUserInfo(state, payload) {
			for (let key in payload) {
				this.commit('$uStore', {
					name: 'userinfo.' + key,
					value: payload[key]
				})
			}
		},
		setPageTheme(state, payload) {
			state.currentTheme = payload
		},
		setCartGoodsNum(state, payload) {
			state.cartGoodsNum = payload
		},
		setCartAmountMoney(state, payload) {
			state.cartAmountMoney = payload
		},
		setCartGoodsIds(state, payload) {
			state.cartGoodsIds = payload
		},
	},
	actions: {
		setGoTop({
			commit,
			state
		}) {

			state.tabBarList[0].selectedIconPath = "/template/h5/default/static/img/tabbar/zhiding.png"




			state.tabBarList[0].text = "回到顶部"
		},
		removeGoTop({
			commit,
			state
		}) {

			state.tabBarList[0].selectedIconPath = "/template/h5/default/static/img/tabbar/home-on.png"




			state.tabBarList[0].text = "首页"
		},
		logout({
			commit,
			state
		}) {
			return new Promise((resolve, reject) => {
				commit('logout')
				resolve()
			})
		},
		// 修改商品列表样式
		toggleCategoryListType({
			commit,
			state
		}, type) {
			state.goodsCateListType = type
			commit('$uStore', {
				name: 'goodsCateListType',
				value: type
			})
		},
		// 获取程序运行设备信息
		setDeviceInfo({
			commit,
			state
		}, data) {
			const {
				height,
				model,
				platform,
				screenHeight,
				top,
				windowBottom,
				windowHeight
			} = data
			state.deviceInfo = Object.assign(state.deviceInfo, {
				height,
				model,
				platform,
				screenHeight,
				top,
				windowBottom,
				windowHeight
			})
			commit('$uStore', {
				name: 'deviceInfo',
				value: state.deviceInfo
			})
		},
		// 设置系统配置数据
		setSystemConfig({
			commit,
			state,
			getters,
			dispatch
		}, value) {
			commit('$uStore', {
				name: 'sysconfig',
				value
			})
			console.log(value);
			const {
				login_menu
			} = value
			// 判断游客商品分类是否允许查看
			let copy_list = [...state.whitePageList]
			if (login_menu.is_login_category_goodslist == 1) {
				let index = copy_list.findIndex(item => item == '/pages/category/index')
				if (index != -1)
					copy_list.splice(index, 1)
			}
			if (login_menu.is_login_goods_detail == 1) {
				let index = copy_list.findIndex(item => item == '/pages/goods/detail')
				if (index != -1)
					copy_list.splice(index, 1)
			}
			if (login_menu.is_login_goods_price_log == 1) {
				let index = copy_list.findIndex(item => item == '/pages/index_sub/pricelog')
				if (index != -1)
					copy_list.splice(index, 1)
			}
			commit('setWhitePageList', copy_list)

			// 更新tabbar数据
			if (value.addon && value.addon.goodsentity) {
				dispatch('updateCartGoodsNum')
				dispatch('updateCartAmountMoney')

				let cart_item_index = state.tabBarList.findIndex(item => item.text == '购物车')
				if (cart_item_index == -1) {


					state.tabBarList.splice(3, 0, {
						iconPath: "/template/h5/diy/static/img/tabbar/cart.png",
						selectedIconPath: "/template/h5/diy/static/img/tabbar/cart-on.png",
						text: "购物车",
						customIcon: false,
						pagePath: "/pages/cart/index",
					})











				}
			} else {
				let cart_item_index = state.tabBarList.findIndex(item => item.text == '购物车')
				if (cart_item_index != -1) {
					state.tabBarList.splice(cart_item_index, 1)
				}
			}
		},
		// 验证token
		valiToken({
			commit,
			state
		}) {
			Vue.prototype.$u.api.valiToken().then(res => {
				if (res.status != 1) {
					commit('logout')
				}
			})
		},
		// 获取用户信息
		getUserInfo({
			commit,
			state
		}) {
			return new Promise((resolve, reject) => {
				Vue.prototype.$u.api.userinfo().then(res => {
					res.userinfo.isLogin = true
					Vue.prototype.$u.vuex('userinfo', res.userinfo)
					resolve(res.userinfo)
				}).catch(error => {
					reject(error)
				})
			})

		},
		// 加载diy页面数据
		getPageData({
			commit,
			state
		}, path) {
			return new Promise(async (resolve, reject) => {
				let find = state.diyPageStack.list.find(item => item.path === path)
				// console.log('diy缓存页面列表', state.diyPageStack.list)
				if (find && find.diyData) {
					const res = await Vue.prototype.$u.api.getDiyVersion({
						url: path
					})
					if (find.diyVersion !== (res.version + '0')) {
						commit('updateDiyData', {
							path,
							data: {
								key: 'diyVersion',
								value: res.version + '0'
							},
						})
						const diyData = await Vue.prototype.$u.api.getDiyPageData({
							url: path
						})
						commit('updateDiyData', {
							path,
							data: {
								key: 'diyData',
								value: diyData
							},
						})
						resolve({
							needReload: true,
							diyData
						})
					} else {
						resolve({
							needReload: false,
							diyData: find.diyData
						})
					}
				} else {
					const diyData = await Vue.prototype.$u.api.getDiyPageData({
						url: path
					})
					commit('addDiyData', {
						path,
						diyData: diyData,
					})
					commit('updateDiyData', {
						path,
						data: {
							key: 'diyVersion',
							value: diyData.version + '0'
						},
					})
					resolve({
						needReload: true,
						diyData
					})
				}
			})
		},
		// 预加载缓存diy页面主题方案
		async reploadCachePageTheme({
			commit,
			state
		}, path) {
			let find = state.diyPageStack.list.find(item => item.path === path)
			if (find && find.diyData) {
				// 这里不需要判断diyData是否过期
				const {
					is_theme_config,
					theme_config
				} = find.diyData

				let viewColor = ''
				if (is_theme_config) {
					const {
						theme,
						priceColor,
						bntColor,
						gradient,
						minorColor,
						minorColorT
					} = theme_config
					viewColor =
						`--view-theme: ${theme};--view-priceColor:${priceColor};--view-minorColor:${minorColor};--view-minorColorT:${minorColorT};--view-bntColor:${bntColor};--view-gradient:${gradient}`
				} else {
					const {
						theme,
						priceColor,
						bntColor,
						gradient,
						minorColor,
						minorColorT
					} = defaultTheme
					viewColor =
						`--view-theme: ${theme};--view-priceColor:${priceColor};--view-minorColor:${minorColor};--view-minorColorT:${minorColorT};--view-bntColor:${bntColor};--view-gradient:${gradient}`
				}
				commit('setPageTheme', {
					path,
					diyData: viewColor,
				})
				return viewColor
			} else {
				return null
			}
		},
		// 更新购物车商品数量
		updateCartGoodsNum({
			commit,
			state,
			getters
		}) {
			if (getters.token) {
				Vue.prototype.$u.api.goodsCartCount().then((res) => {
					commit('setCartGoodsNum', res.count)
				})
			}
		},
		// 更新购物车总计金额
		async updateCartAmountMoney({
			commit,
			state,
			getters
		}) {
			if (getters.token) {
				const data = await Vue.prototype.$u.api.goodsCart({
					only_goods: 1
				})
				let money = 0
				let cartGoodsIds = []
				if (Array.isArray(data))
					data.forEach(item => {
						cartGoodsIds.push(item.id)
						let unit_price = Vue.prototype.$util.bcadd(money, item.goods.goods_price)
						money = Vue.prototype.$util.bcmul(unit_price, item.num)
					})

				commit('setCartAmountMoney', money)
				commit('setCartGoodsIds', cartGoodsIds)
				return money
			}
		},
	},
	getters: {
		userinfo: state => state.userinfo,
		sysconfig: state => state.sysconfig,
		goodsCateListType: state => state.goodsCateListType,
		token: state => state.token,
		deviceInfo: state => state.deviceInfo,
		whitePageList: state => state.whitePageList,
		indexData: (state) => state.indexData,
		diyPageList: state => state.diyPageList,
		currentTheme: state => state.currentTheme,
		defaultTheme: state => state.defaultTheme,
		cartGoodsNum: state => state.cartGoodsNum,
		cartAmountMoney: state => state.cartAmountMoney,
		cartGoodsIds: state => state.cartGoodsIds,
		viewMinGoodsPrice: (state) => state.sysconfig.goods.view_min_goods_price
	},
	modules
})

export default store